// 🌐 Runs when the Student Registration web form loads
console.log("Student Registration Web Form loaded");
console.log("Current user:", frappe.session.user);

// 🧑‍💼 If user is logged in (not Guest), try to auto-fill parent fields


// 🔁 Optional: React when 'i_am' field changes (e.g. Parent / Student)
frappe.web_form.on('i_am', function(field, value) {
    console.log("Registration as:", value);
    const iAm = frappe.web_form.get_value('i_am');
    if (frappe.session.user !== 'Guest' && iAm === 'Student') {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'User',
            fieldname: [ 'email','role_profile_name'],
            filters: { name: frappe.session.user }
        },
        callback: function(r) {
            if (r.message) {
                const user = r.message;
                //const parentName = user.full_name;
                const studentEmail = user.email;
                //const parentUsername = user.email.split('@')[0]; // Simple username from email

                // Set values only if fields exist (safe)
                //frappe.web_form.set_value('parent_name', parentName);
                frappe.web_form.set_value('student_email', studentEmail);
                frappe.web_form.set_df_property('student_email', 'read_only', 1);
                //frappe.web_form.set_value('parent_username', parentUsername);

                // Optional: Show message
                frappe.msgprint({
                    message: 'Welcome back!',
                    title: 'Auto-fill Complete',
                    indicator: 'green'
                });
            }
        }
    });
} else if (frappe.session.user !== 'Guest' && iAm === 'Parent' ) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'User',
            fieldname: [ 'email','role_profile_name'],
            filters: { name: frappe.session.user }
        },
        callback: function(r) {
            if (r.message) {
                const user = r.message;
                //const parentName = user.full_name;
                const parentEmail = user.email;
                //const parentUsername = user.email.split('@')[0]; // Simple username from email

                // Set values only if fields exist (safe)
                //frappe.web_form.set_value('parent_name', parentName);
                frappe.web_form.set_value('parent_email', parentEmail);
                frappe.web_form.set_df_property('parent_email', 'read_only', 1);
                //frappe.web_form.set_value('parent_username', parentUsername);

                // Optional: Show message
                frappe.msgprint({
                    message: 'Welcome back!',
                    title: 'Auto-fill Complete',
                    indicator: 'green'
                });
            }
        }
    });
}  

else {
    console.log("Guest user — Student fields will be validated on submit");
}
});

// ✅ Validation: Enforce parent fields only if Guest and registering as Parent
frappe.web_form.validate = function() {
    const user = frappe.session.user;
    const iAm = frappe.web_form.get_value('i_am');

    // Only validate if Guest and registering as Parent
    if (user === 'Guest' && iAm === 'Parent') {
        const parentEmail = frappe.web_form.get_value('parent_email');
        const parentUsername = frappe.web_form.get_value('parent_username');
        const parentPhone = frappe.web_form.get_value('parent_phone');

        const missing = [];
        if (!parentEmail) missing.push('Parent Email');
        if (!parentUsername) missing.push('Parent Username');
        if (!parentPhone) missing.push('Parent Phone');

        if (missing.length > 0) {
            frappe.msgprint({
                message: `Please fill in the following required fields:<br><br><ul><li>${missing.join('</li><li>')}</li></ul>`,
                title: 'Missing Information',
                indicator: 'red'
            });
            return false; // Prevent form submission
        }
    }

    // ✅ All validations passed
    return true;
};
